"""CSV parser for benchmark results and analysis output."""

import csv
import pandas as pd
from typing import List, Dict, Any
from pathlib import Path

from ..calculators.utilization import BenchmarkResults, UtilizationMetrics


class BenchmarkCSVParser:
    """Parser for benchmark CSV files generated by run_mixtral_benchmark_sweep.sh."""
    
    @staticmethod
    def parse_benchmark_csv(csv_path: str) -> List[BenchmarkResults]:
        """Parse benchmark CSV file into BenchmarkResults objects.
        
        Args:
            csv_path: Path to the benchmark CSV file
            
        Returns:
            List of BenchmarkResults objects
            
        Raises:
            FileNotFoundError: If CSV file doesn't exist
            ValueError: If CSV format is invalid
        """
        csv_file = Path(csv_path)
        if not csv_file.exists():
            raise FileNotFoundError(f"CSV file not found: {csv_path}")
        
        results = []
        
        try:
            with open(csv_file, 'r') as f:
                reader = csv.DictReader(f)
                
                for row in reader:
                    # Skip error rows
                    if row.get('system_throughput') == 'ERROR':
                        continue
                    
                    # Parse and convert types
                    result = BenchmarkResults(
                        input_len=int(row['input_len']),
                        output_len=int(row['output_len']),
                        batch_size=int(row['batch_size']),
                        tp_size=int(row['tp_size']),
                        ep_enabled=row['ep_enabled'].lower() == 'true',
                        system_throughput=float(row['system_throughput']),
                        request_throughput=float(row['request_throughput']),
                        avg_prefill_time=float(row['avg_prefill_time']),
                        avg_decode_time=float(row['avg_decode_time']),
                    )
                    results.append(result)
                    
        except Exception as e:
            raise ValueError(f"Error parsing CSV file: {e}")
        
        return results
    
    @staticmethod
    def get_expected_columns() -> List[str]:
        """Get list of expected columns in benchmark CSV.
        
        Returns:
            List of expected column names
        """
        return [
            'input_len', 'output_len', 'batch_size', 'tp_size', 'ep_enabled',
            'system_throughput', 'request_throughput', 'avg_prefill_time', 
            'avg_decode_time', 'mean_ttft', 'mean_tpot', 'itl_mean', 
            'itl_median', 'itl_p99'
        ]
    
    @staticmethod
    def validate_csv_format(csv_path: str) -> bool:
        """Validate that CSV has the expected format.
        
        Args:
            csv_path: Path to CSV file
            
        Returns:
            True if format is valid, False otherwise
        """
        try:
            with open(csv_path, 'r') as f:
                reader = csv.DictReader(f)
                headers = reader.fieldnames
                expected = BenchmarkCSVParser.get_expected_columns()
                
                # Check that all required columns are present
                missing = set(expected) - set(headers)
                if missing:
                    print(f"Missing required columns: {missing}")
                    return False
                
                return True
                
        except Exception as e:
            print(f"Error validating CSV: {e}")
            return False


class AnalysisCSVWriter:
    """Writer for analysis results with MFU/MBU metrics."""
    
    @staticmethod
    def write_analysis_csv(
        output_path: str,
        benchmark_results: List[BenchmarkResults],
        utilization_results: List[UtilizationMetrics],
        hardware_name: str,
        model_name: str,
        dtype: str
    ) -> None:
        """Write analysis results to CSV file.
        
        Args:
            output_path: Path for output CSV file
            benchmark_results: Original benchmark results
            utilization_results: Calculated utilization metrics
            hardware_name: Name of hardware used
            model_name: Name of model used
            dtype: Data type used for computation
        """
        if len(benchmark_results) != len(utilization_results):
            raise ValueError("Benchmark and utilization results must have same length")
        
        # Prepare data for CSV
        rows = []
        for bench, util in zip(benchmark_results, utilization_results):
            row = {
                # Original benchmark data
                'input_len': bench.input_len,
                'output_len': bench.output_len,
                'batch_size': bench.batch_size,
                'tp_size': bench.tp_size,
                'ep_enabled': bench.ep_enabled,
                'system_throughput': bench.system_throughput,
                'request_throughput': bench.request_throughput,
                'avg_prefill_time': bench.avg_prefill_time,
                'avg_decode_time': bench.avg_decode_time,
                
                # Analysis metadata
                'hardware': hardware_name,
                'model': model_name,
                'dtype': dtype,
                
                # Utilization metrics (as percentages)
                'total_mfu': f"{util.total_mfu:.4f}",
                'total_mbu': f"{util.total_mbu:.4f}",
                'prefill_mfu': f"{util.prefill_mfu:.4f}",
                'prefill_mbu': f"{util.prefill_mbu:.4f}",
                'decode_mfu': f"{util.decode_mfu:.4f}",
                'decode_mbu': f"{util.decode_mbu:.4f}",
                
                # Raw FLOP metrics (TFLOPS)
                'actual_total_flops_tflops': f"{util.actual_total_flops_per_sec:.4f}",
                'actual_prefill_flops_tflops': f"{util.actual_prefill_flops_per_sec:.4f}",
                'actual_decode_flops_tflops': f"{util.actual_decode_flops_per_sec:.4f}",
                
                # Raw memory bandwidth metrics (GB/s)
                'actual_total_memory_bw_gb_s': f"{util.actual_total_memory_bw_gb_s:.4f}",
                'actual_prefill_memory_bw_gb_s': f"{util.actual_prefill_memory_bw_gb_s:.4f}",
                'actual_decode_memory_bw_gb_s': f"{util.actual_decode_memory_bw_gb_s:.4f}",
            }
            rows.append(row)
        
        # Write to CSV
        fieldnames = rows[0].keys() if rows else []
        
        with open(output_path, 'w', newline='') as f:
            writer = csv.DictWriter(f, fieldnames=fieldnames)
            writer.writeheader()
            writer.writerows(rows)
    
    @staticmethod
    def get_analysis_columns() -> List[str]:
        """Get list of columns in analysis CSV output.
        
        Returns:
            List of analysis column names
        """
        return [
            # Original benchmark columns
            'input_len', 'output_len', 'batch_size', 'tp_size', 'ep_enabled',
            'system_throughput', 'request_throughput', 'avg_prefill_time', 'avg_decode_time',
            
            # Analysis metadata
            'hardware', 'model', 'dtype',
            
            # Utilization metrics
            'total_mfu', 'total_mbu', 'prefill_mfu', 'prefill_mbu', 'decode_mfu', 'decode_mbu',
            
            # Raw metrics
            'actual_total_flops_tflops', 'actual_prefill_flops_tflops', 'actual_decode_flops_tflops',
            'actual_total_memory_bw_gb_s', 'actual_prefill_memory_bw_gb_s', 'actual_decode_memory_bw_gb_s',
        ]


def analyze_benchmark_csv(
    input_csv_path: str,
    output_csv_path: str,
    hardware_name: str,
    model_name: str,
    dtype: str = 'fp16'
) -> None:
    """Convenience function to analyze a benchmark CSV file.
    
    Args:
        input_csv_path: Path to input benchmark CSV
        output_csv_path: Path for output analysis CSV
        hardware_name: Name of hardware (e.g., 'A100')
        model_name: Name of model (e.g., 'Mixtral-8x7B')
        dtype: Data type for computation
    """
    from ..hardware.registry import get_hardware
    from ..models.registry import get_model
    from ..calculators.utilization import UtilizationCalculator
    
    # Load hardware and model specifications
    hardware = get_hardware(hardware_name)
    model = get_model(model_name)
    
    # Parse benchmark results
    benchmark_results = BenchmarkCSVParser.parse_benchmark_csv(input_csv_path)
    
    # Calculate utilization metrics
    calculator = UtilizationCalculator(hardware, model, dtype)
    utilization_results = [
        calculator.calculate_utilization(result) 
        for result in benchmark_results
    ]
    
    # Write analysis results
    AnalysisCSVWriter.write_analysis_csv(
        output_csv_path,
        benchmark_results,
        utilization_results,
        hardware_name,
        model_name,
        dtype
    )
    
    print(f"Analysis complete. Results written to: {output_csv_path}")
    print(f"Analyzed {len(benchmark_results)} benchmark configurations.")
    
    # Print summary statistics
    if utilization_results:
        avg_total_mfu = sum(u.total_mfu for u in utilization_results) / len(utilization_results)
        avg_total_mbu = sum(u.total_mbu for u in utilization_results) / len(utilization_results)
        print(f"Average Total MFU: {avg_total_mfu:.4f} ({avg_total_mfu*100:.2f}%)")
        print(f"Average Total MBU: {avg_total_mbu:.4f} ({avg_total_mbu*100:.2f}%)")